"use strict";parserFactory.register("novelcrush.com",()=>new NovelCrushParser);class NovelCrushParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.page-content-listing");return util.hyperlinksToChapterList(t).reverse()}findContent(e){return e.querySelector("div.text-left div.reading-content")}extractTitleImpl(e){return e.querySelector("div.post-title h1")}extractAuthor(e){let t=e.querySelector("div.author-content a");return null===t?super.extractAuthor(e):t.textContent}findChapterTitle(e){return e.querySelector("ol.breadcrumb li.active").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}preprocessRawDom(e){util.removeChildElementsMatchingSelector(e,"ins[data-ad-format]")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary__content")]}cleanInformationNode(e){return util.removeChildElementsMatchingSelector(e,"div.heateor_sss_sharing_container"),e}}